aboxCommand:
set -euo pipefail
tmpdir="$(mktemp -d)"
cat <<'BAKUDO_PACKAGE_JSON' > "$tmpdir/package.json"
{
  "type": "module"
}

BAKUDO_PACKAGE_JSON
cat <<'BAKUDO_PROTOCOL_JS' > "$tmpdir/protocol.js"
export const BAKUDO_PROTOCOL_SCHEMA_VERSION = 1;
export const terminalTaskStatuses = [
    "succeeded",
    "failed",
    "blocked",
    "cancelled",
    "needs_review",
];
export const taskProgressEventKinds = [
    "task.queued",
    "task.started",
    "task.progress",
    "task.checkpoint",
    "task.completed",
    "task.failed",
];
export const isTerminalTaskStatus = (status) => terminalTaskStatuses.includes(status);
export const isTaskProgressEventKind = (kind) => taskProgressEventKinds.includes(kind);
export const createTaskSessionKey = (sessionId, taskId) => `${sessionId}:${taskId}`;

BAKUDO_PROTOCOL_JS
cat <<'BAKUDO_WORKER_RUNTIME_JS' > "$tmpdir/workerRuntime.js"
import { spawn } from "node:child_process";
import { BAKUDO_PROTOCOL_SCHEMA_VERSION, } from "./protocol.js";
export const WORKER_EVENT_PREFIX = "BAKUDO_WORKER_EVENT";
export const WORKER_RESULT_PREFIX = "BAKUDO_WORKER_RESULT";
export const WORKER_ERROR_PREFIX = "BAKUDO_WORKER_ERROR";
const DEFAULT_TIMEOUT_SECONDS = 120;
const DEFAULT_MAX_OUTPUT_BYTES = 256 * 1024;
const DEFAULT_HEARTBEAT_INTERVAL_MS = 5000;
const DEFAULT_KILL_GRACE_MS = 2000;
const isObject = (value) => typeof value === "object" && value !== null && !Array.isArray(value);
const clampPositiveInteger = (value, fallback) => Number.isFinite(value) && value > 0 ? Math.floor(value) : fallback;
const normalizeBase64 = (value) => {
    const trimmed = value.trim().replace(/\s+/g, "");
    const base64 = trimmed.replace(/-/g, "+").replace(/_/g, "/");
    const remainder = base64.length % 4;
    return remainder === 0 ? base64 : `${base64}${"=".repeat(4 - remainder)}`;
};
const captureChunk = (capture, chunk, maxBytes) => {
    if (capture.bytes >= maxBytes) {
        capture.truncated = true;
        return;
    }
    const remaining = maxBytes - capture.bytes;
    if (chunk.length <= remaining) {
        capture.chunks.push(chunk);
        capture.bytes += chunk.length;
        return;
    }
    capture.chunks.push(chunk.subarray(0, remaining));
    capture.bytes += remaining;
    capture.truncated = true;
};
const decodeJson = (encoded) => {
    const normalized = normalizeBase64(encoded);
    const decoded = Buffer.from(normalized, "base64").toString("utf8");
    return JSON.parse(decoded);
};
const makeCapture = () => ({ chunks: [], bytes: 0, truncated: false });
const captureToString = (capture) => Buffer.concat(capture.chunks, capture.bytes).toString("utf8");
const formatMessage = (goal) => {
    const trimmed = goal.trim().replace(/\s+/g, " ");
    return trimmed.length <= 96 ? trimmed : `${trimmed.slice(0, 93)}...`;
};
const nowIso = (now) => (now ?? (() => new Date()))().toISOString();
const emitProgress = (emit, spec, kind, status, message, extra = {}) => {
    emit({
        schemaVersion: BAKUDO_PROTOCOL_SCHEMA_VERSION,
        kind,
        taskId: spec.taskId,
        sessionId: spec.sessionId,
        status,
        message,
        timestamp: nowIso(),
        ...extra,
    });
};
const validateTaskSpec = (value) => {
    if (!isObject(value)) {
        throw new Error("invalid task spec: expected JSON object");
    }
    const schemaVersion = value.schemaVersion;
    if (schemaVersion !== BAKUDO_PROTOCOL_SCHEMA_VERSION) {
        throw new Error(`unsupported task spec schema version: ${String(schemaVersion)} (expected ${BAKUDO_PROTOCOL_SCHEMA_VERSION})`);
    }
    const taskId = value.taskId;
    const sessionId = value.sessionId;
    const goal = value.goal;
    const assumeDangerousSkipPermissions = value.assumeDangerousSkipPermissions;
    if (typeof taskId !== "string" || taskId.trim().length === 0) {
        throw new Error("invalid task spec: missing taskId");
    }
    if (typeof sessionId !== "string" || sessionId.trim().length === 0) {
        throw new Error("invalid task spec: missing sessionId");
    }
    if (typeof goal !== "string" || goal.trim().length === 0) {
        throw new Error("invalid task spec: missing goal");
    }
    if (typeof assumeDangerousSkipPermissions !== "boolean") {
        throw new Error("invalid task spec: missing assumeDangerousSkipPermissions");
    }
    const cwd = value.cwd;
    const streamId = value.streamId;
    const timeoutSeconds = value.timeoutSeconds;
    const maxOutputBytes = value.maxOutputBytes;
    const heartbeatIntervalMs = value.heartbeatIntervalMs;
    return {
        schemaVersion,
        taskId,
        sessionId,
        goal,
        assumeDangerousSkipPermissions,
        ...(typeof streamId === "string" && streamId.trim().length > 0 ? { streamId } : {}),
        ...(typeof cwd === "string" && cwd.trim().length > 0 ? { cwd } : {}),
        ...(typeof timeoutSeconds === "number" && Number.isFinite(timeoutSeconds)
            ? { timeoutSeconds }
            : {}),
        ...(typeof maxOutputBytes === "number" && Number.isFinite(maxOutputBytes)
            ? { maxOutputBytes }
            : {}),
        ...(typeof heartbeatIntervalMs === "number" && Number.isFinite(heartbeatIntervalMs)
            ? { heartbeatIntervalMs }
            : {}),
    };
};
export const decodeWorkerTaskSpec = (encoded) => validateTaskSpec(decodeJson(encoded));
export const encodeWorkerEnvelope = (prefix, payload) => `${prefix} ${JSON.stringify(payload)}`;
export const parseWorkerTaskSpec = (argv) => {
    const specArg = argv.find((arg) => arg === "--task-spec-b64" || arg.startsWith("--task-spec-b64="));
    if (!specArg) {
        throw new Error("missing required argument --task-spec-b64");
    }
    const encoded = specArg.includes("=")
        ? specArg.slice("--task-spec-b64=".length)
        : (() => {
            const index = argv.indexOf(specArg);
            const value = argv[index + 1];
            if (value === undefined || value.startsWith("--")) {
                throw new Error("missing value for --task-spec-b64");
            }
            return value;
        })();
    return decodeWorkerTaskSpec(encoded);
};
export const workerResultStatusFromExitCode = (exitCode, timedOut) => (exitCode === 0 && !timedOut ? "succeeded" : "failed");
export const runWorkerTask = async (spec, options = {}) => {
    const runtimeProcess = process;
    const emit = options.emit ?? (() => undefined);
    const shell = options.shell ?? "bash";
    const timeoutSeconds = clampPositiveInteger(options.timeoutSeconds ?? spec.timeoutSeconds ?? DEFAULT_TIMEOUT_SECONDS, DEFAULT_TIMEOUT_SECONDS);
    const maxOutputBytes = clampPositiveInteger(options.maxOutputBytes ?? spec.maxOutputBytes ?? DEFAULT_MAX_OUTPUT_BYTES, DEFAULT_MAX_OUTPUT_BYTES);
    const heartbeatIntervalMs = clampPositiveInteger(options.heartbeatIntervalMs ?? spec.heartbeatIntervalMs ?? DEFAULT_HEARTBEAT_INTERVAL_MS, DEFAULT_HEARTBEAT_INTERVAL_MS);
    const killGraceMs = clampPositiveInteger(options.killGraceMs ?? DEFAULT_KILL_GRACE_MS, DEFAULT_KILL_GRACE_MS);
    const cwd = spec.cwd ?? runtimeProcess.cwd?.() ?? ".";
    const startedAt = nowIso(options.now);
    emitProgress(emit, spec, "task.queued", "queued", "task accepted for execution", {
        percentComplete: 0,
    });
    emitProgress(emit, spec, "task.started", "running", `running ${formatMessage(spec.goal)}`);
    const stdoutCapture = makeCapture();
    const stderrCapture = makeCapture();
    let exitCode = null;
    let exitSignal = null;
    let timedOut = false;
    let failedToSpawn = null;
    const child = spawn(shell, ["-lc", spec.goal], {
        cwd,
        env: runtimeProcess.env,
        stdio: ["ignore", "pipe", "pipe"],
    });
    const heartbeat = setInterval(() => {
        const elapsedMs = Date.now() - Date.parse(startedAt);
        emitProgress(emit, spec, "task.progress", "running", `running for ${Math.max(0, elapsedMs)}ms`, {
            elapsedMs: Math.max(0, elapsedMs),
            stdoutBytes: stdoutCapture.bytes,
            stderrBytes: stderrCapture.bytes,
        });
    }, heartbeatIntervalMs);
    heartbeat.unref?.();
    const timeoutHandle = setTimeout(() => {
        timedOut = true;
        emitProgress(emit, spec, "task.progress", "running", `timeout after ${timeoutSeconds}s, stopping command`, {
            timedOut: true,
        });
        child.kill("SIGTERM");
        const forceKill = setTimeout(() => {
            if (child.exitCode === null && child.signalCode === null) {
                child.kill("SIGKILL");
            }
        }, killGraceMs);
        forceKill.unref?.();
    }, timeoutSeconds * 1000);
    timeoutHandle.unref?.();
    child.stdout?.on("data", (chunk) => {
        captureChunk(stdoutCapture, chunk, maxOutputBytes);
        emitProgress(emit, spec, "task.progress", "running", "captured stdout output", {
            stdoutBytes: stdoutCapture.bytes,
            stderrBytes: stderrCapture.bytes,
        });
    });
    child.stderr?.on("data", (chunk) => {
        captureChunk(stderrCapture, chunk, maxOutputBytes);
        emitProgress(emit, spec, "task.progress", "running", "captured stderr output", {
            stdoutBytes: stdoutCapture.bytes,
            stderrBytes: stderrCapture.bytes,
        });
    });
    await new Promise((resolve, reject) => {
        child.once("error", (error) => {
            failedToSpawn = error instanceof Error ? error : new Error(String(error));
            reject(failedToSpawn);
        });
        child.once("exit", (code, signal) => {
            exitCode = code;
            exitSignal = signal;
            resolve();
        });
    }).catch(() => undefined);
    clearInterval(heartbeat);
    clearTimeout(timeoutHandle);
    const finishedAt = nowIso(options.now);
    const stdout = captureToString(stdoutCapture);
    const stderr = captureToString(stderrCapture);
    const command = spec.goal;
    const status = failedToSpawn ? "failed" : workerResultStatusFromExitCode(exitCode, timedOut);
    const summary = failedToSpawn
        ? `failed to start command: ${failedToSpawn.message}`
        : timedOut
            ? `command timed out after ${timeoutSeconds}s`
            : exitCode === 0
                ? "command completed successfully"
                : `command exited with code ${String(exitCode ?? "unknown")}`;
    const result = {
        schemaVersion: BAKUDO_PROTOCOL_SCHEMA_VERSION,
        taskId: spec.taskId,
        sessionId: spec.sessionId,
        status,
        summary,
        exitCode,
        startedAt,
        finishedAt,
        ...(stdout || stderr ? { artifacts: ["stdout", "stderr"] } : {}),
        command,
        cwd,
        shell,
        timeoutSeconds,
        durationMs: Math.max(0, Date.parse(finishedAt) - Date.parse(startedAt)),
        exitSignal,
        stdout,
        stderr,
        stdoutTruncated: stdoutCapture.truncated,
        stderrTruncated: stderrCapture.truncated,
        timedOut,
        assumeDangerousSkipPermissions: spec.assumeDangerousSkipPermissions,
    };
    if (status === "succeeded") {
        emitProgress(emit, spec, "task.completed", "succeeded", result.summary, {
            exitCode,
            exitSignal,
            elapsedMs: result.durationMs,
            stdoutBytes: stdoutCapture.bytes,
            stderrBytes: stderrCapture.bytes,
        });
    }
    else {
        emitProgress(emit, spec, "task.failed", "failed", result.summary, {
            exitCode,
            exitSignal,
            timedOut,
            elapsedMs: result.durationMs,
            stdoutBytes: stdoutCapture.bytes,
            stderrBytes: stderrCapture.bytes,
        });
    }
    return result;
};
export const serializeWorkerEvent = (event) => encodeWorkerEnvelope(WORKER_EVENT_PREFIX, event);
export const serializeWorkerResult = (result) => encodeWorkerEnvelope(WORKER_RESULT_PREFIX, result);
export const serializeWorkerError = (message, details) => encodeWorkerEnvelope(WORKER_ERROR_PREFIX, {
    schemaVersion: BAKUDO_PROTOCOL_SCHEMA_VERSION,
    message,
    ...(details ?? {}),
});

BAKUDO_WORKER_RUNTIME_JS
cat <<'BAKUDO_WORKER_CLI_JS' > "$tmpdir/workerCli.js"
#!/usr/bin/env node
import { parseWorkerTaskSpec, runWorkerTask, serializeWorkerError, serializeWorkerEvent, serializeWorkerResult, } from "./workerRuntime.js";
import { isMainModule } from "./mainModule.js";
const parsePositiveInteger = (value, fallback, name) => {
    if (value === undefined) {
        return fallback;
    }
    const parsed = Number.parseInt(value, 10);
    if (!Number.isFinite(parsed) || parsed <= 0) {
        throw new Error(`invalid ${name}: expected positive integer`);
    }
    return parsed;
};
const readLongFlag = (argv, index, flag) => {
    const arg = argv[index];
    if (typeof arg !== "string") {
        throw new Error(`missing argument for ${flag}`);
    }
    if (arg === flag) {
        const value = argv[index + 1];
        if (value === undefined || value.startsWith("--")) {
            throw new Error(`missing value for ${flag}`);
        }
        return { value, consumed: 2 };
    }
    if (arg.startsWith(`${flag}=`)) {
        return { value: arg.slice(flag.length + 1), consumed: 1 };
    }
    throw new Error(`unexpected argument reader call for ${arg}`);
};
export const parseWorkerArgs = (argv) => {
    const result = {
        taskSpecB64: "",
        shell: "bash",
        timeoutSeconds: 120,
        maxOutputBytes: 256 * 1024,
        heartbeatIntervalMs: 5000,
        killGraceMs: 2000,
        help: false,
    };
    for (let i = 0; i < argv.length; i += 1) {
        const arg = argv[i];
        if (typeof arg !== "string") {
            continue;
        }
        if (arg === "--help" || arg === "-h") {
            result.help = true;
            continue;
        }
        if (arg === "--task-spec-b64" || arg.startsWith("--task-spec-b64=")) {
            const { value, consumed } = readLongFlag(argv, i, "--task-spec-b64");
            result.taskSpecB64 = value;
            i += consumed - 1;
            continue;
        }
        if (arg === "--shell" || arg.startsWith("--shell=")) {
            const { value, consumed } = readLongFlag(argv, i, "--shell");
            result.shell = value;
            i += consumed - 1;
            continue;
        }
        if (arg === "--timeout-seconds" || arg.startsWith("--timeout-seconds=")) {
            const { value, consumed } = readLongFlag(argv, i, "--timeout-seconds");
            result.timeoutSeconds = parsePositiveInteger(value, result.timeoutSeconds, "--timeout-seconds");
            i += consumed - 1;
            continue;
        }
        if (arg === "--max-output-bytes" || arg.startsWith("--max-output-bytes=")) {
            const { value, consumed } = readLongFlag(argv, i, "--max-output-bytes");
            result.maxOutputBytes = parsePositiveInteger(value, result.maxOutputBytes, "--max-output-bytes");
            i += consumed - 1;
            continue;
        }
        if (arg === "--heartbeat-ms" || arg.startsWith("--heartbeat-ms=")) {
            const { value, consumed } = readLongFlag(argv, i, "--heartbeat-ms");
            result.heartbeatIntervalMs = parsePositiveInteger(value, result.heartbeatIntervalMs, "--heartbeat-ms");
            i += consumed - 1;
            continue;
        }
        if (arg === "--kill-grace-ms" || arg.startsWith("--kill-grace-ms=")) {
            const { value, consumed } = readLongFlag(argv, i, "--kill-grace-ms");
            result.killGraceMs = parsePositiveInteger(value, result.killGraceMs, "--kill-grace-ms");
            i += consumed - 1;
            continue;
        }
        throw new Error(`unknown argument: ${arg}`);
    }
    return result;
};
const printUsage = () => {
    process.stdout.write([
        "Usage: bakudo-worker --task-spec-b64 <base64-json> [--shell bash] [--timeout-seconds N]",
        "                     [--max-output-bytes N] [--heartbeat-ms N] [--kill-grace-ms N]",
        "",
        "Required task spec fields: schemaVersion, taskId, sessionId, goal, assumeDangerousSkipPermissions",
    ].join("\n") + "\n");
};
export const runWorkerCli = async (argv) => {
    const args = parseWorkerArgs(argv);
    if (args.help) {
        printUsage();
        return 0;
    }
    if (args.taskSpecB64.length === 0) {
        throw new Error("missing required argument --task-spec-b64");
    }
    const spec = parseWorkerTaskSpec(["--task-spec-b64", args.taskSpecB64]);
    const result = await runWorkerTask(spec, {
        shell: args.shell,
        timeoutSeconds: args.timeoutSeconds,
        maxOutputBytes: args.maxOutputBytes,
        heartbeatIntervalMs: args.heartbeatIntervalMs,
        killGraceMs: args.killGraceMs,
        emit: (event) => {
            process.stdout.write(`${serializeWorkerEvent(event)}\n`);
        },
    });
