    return result.status === "succeeded" ? 0 : 1;
};
const printWorkerError = (message, details) => {
    process.stdout.write(`${serializeWorkerError(message, details)}\n`);
};
if (isMainModule(import.meta.url, process.argv[1])) {
    runWorkerCli(process.argv.slice(2))
        .then((code) => {
        process.exitCode = code;
    })
        .catch((error) => {
        const message = error instanceof Error ? error.message : String(error);
        printWorkerError("worker_cli_failed", { message });
        process.exitCode = 2;
    });
}

BAKUDO_WORKER_CLI_JS
node "$tmpdir/workerCli.js" --task-spec-b64 '' --shell 'bash' --timeout-seconds 1800 --max-output-bytes 20971520 --heartbeat-ms 5000 --kill-grace-ms 2000
